import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("processScenario - empty scenario", () => {
    it.todo("should return empty results for scenario with no steps");
  });

  describe("Quoting - base premiums for single main items", () => {
    it.todo("should quote a sword (base 100 G) with processing fee and first-insurance surcharge");
    it.todo("should quote an amulet (base 60 G) with processing fee and first-insurance surcharge");
    it.todo("should quote a staff (base 80 G) with processing fee and first-insurance surcharge");
    it.todo("should quote a potion (base 40 G) with processing fee and first-insurance surcharge");
  });

  describe("Quoting - components", () => {
    it.todo("should quote a single rune at base premium 25 G");
    it.todo("should quote a single moonstone at base premium 25 G");
    it.todo("should quote 2 alike components at 2 x 25 G base premium");
    it.todo("should quote 3 alike runes as a building block at special 60 G base premium");
    it.todo("should quote 3 alike moonstones as a building block at special 60 G base premium");
    it.todo("should not combine unlike components into a building block");
  });

  describe("Quoting - multiple items in one quote", () => {
    it.todo("should sum base premiums of multiple main items in one quote");
  });

  describe("Quoting - risk surcharges", () => {
    it.todo("should add 50% surcharge for a cursed item");
    it.todo("should add 30% surcharge for highly enchanted item (enchantment >= 5)");
    it.todo("should not add enchantment surcharge for enchantment level 4");
    it.todo("should apply both cursed and high-enchantment surcharges when both apply");
  });

  describe("Quoting - customer modifiers", () => {
    it.todo("should apply 10% first-insurance surcharge when customer has no prior contracts");
    it.todo("should apply 15% per-contract discount on the second contract");
    it.todo("should apply 20% loyalty discount for customers with >= 2 years with MHPCO");
    it.todo("should not apply loyalty discount for customers with < 2 years with MHPCO");
  });

  describe("Quoting - processing fee and rounding", () => {
    it.todo("should add a 5 G processing fee to every quote");
    it.todo("should round the final premium up to whole G (in MHPCO's favor)");
  });

  describe("Claims - basics", () => {
    it.todo("should return payout 0 for a claim on a non-reimbursable item (no high enchantment, no dragon material)");
    it.todo("should reimburse 50% of damage amount minus 100 G deductible for items with enchantment >= 8");
    it.todo("should fully reimburse damage amount minus 100 G deductible for dragon-material items");
    it.todo("should apply only one 100 G deductible per claim event covering multiple damaged items");
    it.todo("should return payout 0 when reimbursable amount is less than the deductible");
  });

  describe("End-to-end scenario", () => {
    it.todo("should process a quote followed by a claim against that policy");
  });
});

